import React, { useState, useEffect, useRef } from 'react';
import { 
  User, 
  Crown,
  Server, 
  Code,
  Palette,
  Database,
  BarChart3,
  TrendingUp,
  ChevronRight,
  Cpu,
  Component,
  LineChart,
  MapPin,
  Mail,
  Phone,
  Calendar
} from 'lucide-react';

// Estilos de fuentes
const fontStyles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Montserrat:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;1,100;1,200;1,300;1,400&family=Inter:wght@100;200;300;400;500;600;700&display=swap');
  
  .font-playfair {
    font-family: 'Playfair Display', serif;
  }
  
  .font-montserrat {
    font-family: 'Montserrat', sans-serif;
  }
  
  .font-inter {
    font-family: 'Inter', sans-serif;
  }

  /* Reset específico para botones del header */
  .header-icon-button {
    all: unset;
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    border: none;
    background: none;
    font: inherit;
    color: inherit;
    cursor: pointer;
    outline: none;
  }

  .header-icon-button:focus {
    outline: none;
    ring: none;
  }

  .header-icon-button:hover {
    background: none !important;
    border: none !important;
  }
`;

// Componente Reveal simplificado
const Reveal = ({ children, delay = 0 }) => {
  const [isVisible, setIsVisible] = useState(false);
  
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(true);
    }, delay);
    
    return () => clearTimeout(timer);
  }, [delay]);
  
  return (
    <div className={`transition-all duration-700 ease-out ${
      isVisible 
        ? 'opacity-100 translate-y-0' 
        : 'opacity-0 translate-y-8'
    }`}>
      {children}
    </div>
  );
};

const EquipoPage = () => {
  const [activeSection, setActiveSection] = useState('delegacion');
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const sectionRefs = useRef({});
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);

  // Insertar estilos en el head del documento
  useEffect(() => {
    const styleElement = document.createElement('style');
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
    
    return () => {
      document.head.removeChild(styleElement);
    };
  }, []);

  // Scroll handler para parallax y sticky navigation
  useEffect(() => {
    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }

      // Update active section based on scroll position
      const sections = ['delegacion', 'backend', 'frontend', 'diseno', 'basedatos', 'dashboard', 'unete'];
      const scrollPosition = window.scrollY + 100;

      for (const sectionId of sections) {
        const element = sectionRefs.current[sectionId];
        if (element) {
          const { offsetTop, offsetHeight } = element;
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + offsetHeight) {
            setActiveSection(sectionId);
            break;
          }
        }
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - 150;
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActiveSection(id);
  };

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  // Secciones con los mismos iconos del header
  const sections = [
    { id: 'delegacion', label: 'Liderazgo', icon: Crown, color: 'from-amber-500 to-yellow-600' },
    { id: 'backend', label: 'Backend', icon: Cpu, color: 'from-emerald-500 to-green-600' },
    { id: 'frontend', label: 'Frontend', icon: Component, color: 'from-blue-500 to-cyan-600' },
    { id: 'diseno', label: 'Diseño', icon: Palette, color: 'from-rose-500 to-pink-600' },
    { id: 'basedatos', label: 'Base de Datos', icon: Database, color: 'from-violet-500 to-purple-600' },
    { id: 'dashboard', label: 'Analytics', icon: LineChart, color: 'from-orange-500 to-red-600' }
  ];

  // Logos de los cuerpos con iconos sueltos
  const bodyLogos = [
    { 
      id: 'delegacion', 
      name: 'Liderazgo', 
      icon: Crown, 
      section: 'delegacion'
    },
    { 
      id: 'backend', 
      name: 'Backend', 
      icon: Cpu, 
      section: 'backend'
    },
    { 
      id: 'frontend', 
      name: 'Frontend', 
      icon: Component, 
      section: 'frontend'
    },
    { 
      id: 'diseno', 
      name: 'Diseño', 
      icon: Palette, 
      section: 'diseno'
    },
    { 
      id: 'basedatos', 
      name: 'Base de Datos', 
      icon: Database, 
      section: 'basedatos'
    },
    { 
      id: 'dashboard', 
      name: 'Analytics', 
      icon: LineChart, 
      section: 'dashboard'
    }
  ];

  // Datos de ejemplo del equipo - actualizados
  const teamMembers = {
    delegacion: [
      { 
        id: 1, 
        name: 'Ana Rodríguez', 
        position: 'Project Manager', 
        skills: ['Liderazgo', 'Estrategia', 'Gestión'],
        experience: '8+ años',
        location: 'Madrid, España',
        email: 'ana.rodriguez@orbis.com'
      },
      { 
        id: 2, 
        name: 'Carlos Méndez', 
        position: 'Líder de Equipo', 
        skills: ['Coordinación', 'Planificación', 'Mentoría'],
        experience: '6+ años',
        location: 'Barcelona, España',
        email: 'carlos.mendez@orbis.com'
      },
      { 
        id: 3, 
        name: 'María Fernández', 
        position: 'Coordinadora', 
        skills: ['Organización', 'Comunicación', 'Logística'],
        experience: '5+ años',
        location: 'Valencia, España',
        email: 'maria.fernandez@orbis.com'
      }
    ],
    backend: [
      { 
        id: 1, 
        name: 'Javier López', 
        position: 'Senior Backend Dev', 
        skills: ['Node.js', 'Python', 'APIs'],
        experience: '7+ años',
        location: 'Remote',
        email: 'javier.lopez@orbis.com'
      },
      { 
        id: 2, 
        name: 'Laura Martínez', 
        position: 'API Specialist', 
        skills: ['REST', 'GraphQL', 'Microservicios'],
        experience: '5+ años',
        location: 'Madrid, España',
        email: 'laura.martinez@orbis.com'
      },
      { 
        id: 3, 
        name: 'Diego Ramírez', 
        position: 'DevOps Engineer', 
        skills: ['AWS', 'Docker', 'CI/CD'],
        experience: '6+ años',
        location: 'Sevilla, España',
        email: 'diego.ramirez@orbis.com'
      }
    ],
    frontend: [
      { 
        id: 1, 
        name: 'Sofía García', 
        position: 'Frontend Lead', 
        skills: ['React', 'TypeScript', 'UX'],
        experience: '6+ años',
        location: 'Bilbao, España',
        email: 'sofia.garcia@orbis.com'
      },
      { 
        id: 2, 
        name: 'Miguel Ángel Torres', 
        position: 'UI/UX Developer', 
        skills: ['Figma', 'Prototipado', 'Design Systems'],
        experience: '4+ años',
        location: 'Remote',
        email: 'miguel.torres@orbis.com'
      },
      { 
        id: 3, 
        name: 'Elena Vargas', 
        position: 'React Specialist', 
        skills: ['Hooks', 'Context', 'Performance'],
        experience: '5+ años',
        location: 'Madrid, España',
        email: 'elena.vargas@orbis.com'
      }
    ],
    diseno: [
      { 
        id: 1, 
        name: 'Claudia Rojas', 
        position: 'Diseñadora Gráfica', 
        skills: ['Illustrator', 'Branding', 'Tipografía'],
        experience: '5+ años',
        location: 'Barcelona, España',
        email: 'claudia.rojas@orbis.com'
      },
      { 
        id: 2, 
        name: 'Ricardo Fuentes', 
        position: 'UX Researcher', 
        skills: ['User Testing', 'Wireframes', 'Prototipos'],
        experience: '4+ años',
        location: 'Valencia, España',
        email: 'ricardo.fuentes@orbis.com'
      },
      { 
        id: 3, 
        name: 'Isabel Mendoza', 
        position: 'Diseñadora Visual', 
        skills: ['Photoshop', 'Animación', 'Illustration'],
        experience: '6+ años',
        location: 'Madrid, España',
        email: 'isabel.mendoza@orbis.com'
      }
    ],
    basedatos: [
      { 
        id: 1, 
        name: 'Roberto Silva', 
        position: 'Database Architect', 
        skills: ['SQL', 'MongoDB', 'Optimización'],
        experience: '8+ años',
        location: 'Remote',
        email: 'roberto.silva@orbis.com'
      },
      { 
        id: 2, 
        name: 'Carolina Ríos', 
        position: 'Data Analyst', 
        skills: ['ETL', 'Power BI', 'Estadística'],
        experience: '5+ años',
        location: 'Madrid, España',
        email: 'carolina.rios@orbis.com'
      },
      { 
        id: 3, 
        name: 'Andrés Castillo', 
        position: 'DB Administrator', 
        skills: ['Seguridad', 'Backups', 'Monitorización'],
        experience: '7+ años',
        location: 'Barcelona, España',
        email: 'andres.castillo@orbis.com'
      }
    ],
    dashboard: [
      { 
        id: 1, 
        name: 'Patricia Navarro', 
        position: 'Dashboard Designer', 
        skills: ['DataViz', 'Tableau', 'Storytelling'],
        experience: '5+ años',
        location: 'Remote',
        email: 'patricia.navarro@orbis.com'
      },
      { 
        id: 2, 
        name: 'Fernando Jiménez', 
        position: 'Data Visualization', 
        skills: ['D3.js', 'Chart.js', 'Animaciones'],
        experience: '4+ años',
        location: 'Madrid, España',
        email: 'fernando.jimenez@orbis.com'
      },
      { 
        id: 3, 
        name: 'Gabriela Ortega', 
        position: 'Analytics Specialist', 
        skills: ['KPIs', 'Métricas', 'Business Intelligence'],
        experience: '6+ años',
        location: 'Sevilla, España',
        email: 'gabriela.ortega@orbis.com'
      }
    ]
  };

  return (
    <div className="min-h-screen bg-beige font-inter [&_a]:no-underline [&_a:hover]:no-underline">
      
      {/* HEADER (se mantiene igual) */}
      <div className="h-[80vh] min-h-[400px] max-h-[800px] mb-9 overflow-hidden relative">
        {/* ... header code igual que antes ... */}
      </div>

      <main className="px-10 py-0">
        {/* NAVEGACIÓN MÓVIL */}
        <div className="block lg:hidden mb-8">
          <nav className="flex flex-row gap-2 overflow-x-auto py-4">
            {sections.map((s) => (
              <a
                key={s.id}
                href={`#${s.id}`}
                onClick={(e) => scrollTo(e, s.id)}
                className={`
                  relative text-left py-3 px-4 transition-colors duration-200 whitespace-nowrap
                  rounded-lg border border-[#9298A6]/30 bg-white/10
                  hover:bg-[#9298A6]/10
                  ${
                    activeSection === s.id 
                      ? 'bg-[#9298A6]/20 font-medium'
                      : 'font-light opacity-80 hover:opacity-100'
                  }
                `}
              >
                <span className="tracking-widest text-sm text-[#072D42] font-montserrat">{s.label}</span>
              </a>
            ))}
          </nav>
        </div>

        <div className="flex flex-col lg:flex-row gap-16 lg:items-start">
          {/* ASIDE ELEGANTE - STICKY NAVIGATION */}
          <aside className="hidden lg:block lg:w-1/5 sticky top-1/4">
            <div className={`
              transition-all duration-700 ease-in-out
              ${isHeaderShrunk 
                ? 'opacity-100' 
                : 'opacity-0 -translate-y-4 pointer-events-none'
              }
            `}>
              <h2 className="font-playfair text-2xl leading-tight mb-4 text-[#072D42]">Nuestro Equipo</h2>
              <div className="h-px w-16 bg-[#072D42]/50 mb-6"></div>
            </div>

            <nav className="flex lg:flex-col gap-0 rounded-lg overflow-hidden border border-[#9298A6]/30 bg-white/10">
              {sections.map((s) => (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center justify-between py-3 px-4 transition-all duration-300
                    after:content-[''] after:absolute after:left-0 after:bottom-0
                    after:w-full after:h-[1px] after:bg-[#9298A6]
                    after:origin-center after:transition-transform after:duration-300 after:ease-out
                    border-b border-[#9298A6]/20 last:border-b-0
                    hover:bg-[#9298A6]/10
                    ${
                      activeSection === s.id 
                        ? 'font-medium opacity-100 after:scale-x-100 bg-[#9298A6]/20'
                        : 'font-extralight opacity-70 hover:opacity-100 after:scale-x-0 hover:after:scale-x-100'
                    }
                  `}
                >
                  <div className="flex items-center gap-3">
                    <s.icon className="w-4 h-4 text-[#072D42] opacity-70 group-hover:opacity-100 transition-opacity duration-300" />
                    <span className="tracking-widest text-sm text-[#072D42] font-montserrat font-extralight">
                      {s.label}
                    </span>
                  </div>
                  <div className="opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-x-2 group-hover:translate-x-0">
                    <ChevronRight className="w-3 h-3 text-[#072D42]" />
                  </div>
                </a>
              ))}
            </nav>
          </aside>

          {/* CONTENIDO PRINCIPAL CON NUEVAS TARJETAS */}
          <section className="w-full lg:w-4/5 flex flex-col">
            {sections.map((section, index) => (
              <div key={section.id}>
                {/* LÍNEA SEPARADORA ELEGANTE */}
                {index > 0 && (
                  <div className="flex items-center justify-center my-16">
                    <div className="h-px w-32 bg-[#072D42]/20"></div>
                    <div className="mx-4">
                      <section.icon className="w-6 h-6 text-[#072D42]/40" />
                    </div>
                    <div className="h-px w-32 bg-[#072D42]/20"></div>
                  </div>
                )}

                <div
                  id={section.id}
                  ref={(el) => (sectionRefs.current[section.id] = el)}
                  className="scroll-mt-24"
                >
                  <div className="container mx-auto px-4 sm:px-6 py-12 md:py-16">
                    <Reveal delay={index * 100}>
                      <div className="mb-12 md:mb-16 text-center">
                        <div className="flex items-center justify-center gap-3 mb-4">
                          <section.icon className="w-8 h-8 text-[#072D42]" />
                          <h2 className="font-playfair text-3xl md:text-4xl lg:text-5xl text-[#072D42] font-normal">
                            {section.label}
                          </h2>
                        </div>
                        <div className="h-px w-20 bg-[#072D42]/60 mx-auto"></div>
                      </div>
                    </Reveal>

                    {/* NUEVAS TARJETAS RECTANGULARES CON ICONO A LA DERECHA */}
                    <div className="grid grid-cols-1 gap-8 max-w-6xl mx-auto">
                      {teamMembers[section.id].map((member, memberIndex) => (
                        <Reveal key={member.id} delay={(index * 100) + (memberIndex * 100)}>
                          <div className="bg-white rounded-2xl shadow-xl border border-[#072D42]/10 hover:shadow-2xl hover:border-[#072D42]/20 transition-all duration-500 ease-out group overflow-hidden">
                            <div className="flex flex-col lg:flex-row">
                              {/* CONTENIDO PRINCIPAL - IZQUIERDA */}
                              <div className="flex-1 p-8">
                                <div className="flex items-start gap-6">
                                  {/* Avatar/Icono del miembro */}
                                  <div className="flex-shrink-0">
                                    <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-[#072D42] to-[#0A3A5A] flex items-center justify-center group-hover:scale-105 transition-transform duration-500">
                                      <User className="w-10 h-10 text-white" />
                                    </div>
                                  </div>
                                  
                                  {/* Información del miembro */}
                                  <div className="flex-1">
                                    <h3 className="font-playfair text-2xl text-[#072D42] group-hover:text-[#0A3A5A] font-normal mb-2 transition-colors duration-300">
                                      {member.name}
                                    </h3>
                                    <p className="font-inter text-[#072D42]/80 text-lg mb-3 font-medium">
                                      {member.position}
                                    </p>
                                    
                                    {/* Información adicional */}
                                    <div className="flex flex-wrap gap-4 mb-4">
                                      <div className="flex items-center gap-2 text-sm text-[#072D42]/70">
                                        <Calendar className="w-4 h-4" />
                                        <span>{member.experience}</span>
                                      </div>
                                      <div className="flex items-center gap-2 text-sm text-[#072D42]/70">
                                        <MapPin className="w-4 h-4" />
                                        <span>{member.location}</span>
                                      </div>
                                      <div className="flex items-center gap-2 text-sm text-[#072D42]/70">
                                        <Mail className="w-4 h-4" />
                                        <span>{member.email}</span>
                                      </div>
                                    </div>
                                    
                                    {/* Skills */}
                                    <div className="flex flex-wrap gap-2">
                                      {member.skills.map((skill, skillIndex) => (
                                        <span 
                                          key={skillIndex}
                                          className="inline-flex items-center px-3 py-1 bg-gradient-to-r from-[#F4E9D7] to-[#E8DBC5] text-[#072D42] text-sm rounded-full font-inter border border-[#072D42]/10 group-hover:border-[#072D42]/20 transition-all duration-300"
                                        >
                                          {skill}
                                        </span>
                                      ))}
                                    </div>
                                  </div>
                                </div>
                              </div>
                              
                              {/* ICONO DE LA SECCIÓN - DERECHA */}
                              <div className="lg:w-32 bg-gradient-to-br from-white to-gray-50 border-l border-[#072D42]/5 flex items-center justify-center p-6 group-hover:bg-gradient-to-br group-hover:from-gray-50 group-hover:to-white transition-all duration-500">
                                <div className="relative">
                                  <section.icon className="w-12 h-12 text-[#072D42]/60 group-hover:text-[#072D42] group-hover:scale-110 transition-all duration-500" />
                                  <div className="absolute inset-0 bg-gradient-to-br from-transparent to-transparent rounded-full group-hover:from-white/20 group-hover:to-transparent blur-sm transition-all duration-500"></div>
                                </div>
                              </div>
                            </div>
                          </div>
                        </Reveal>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            ))}

            {/* SECCIÓN "ÚNETE" (se mantiene igual) */}
            <div className="flex items-center justify-center my-16">
              <div className="h-px w-32 bg-[#072D42]/20"></div>
              <div className="mx-4">
                <TrendingUp className="w-6 h-6 text-[#072D42]/40" />
              </div>
              <div className="h-px w-32 bg-[#072D42]/20"></div>
            </div>

            <div 
              id="unete"
              ref={(el) => (sectionRefs.current.unete = el)}
              className="scroll-mt-24 relative min-h-[500px]"
            >
              {/* ... sección únete igual que antes ... */}
            </div>
          </section>
        </div>
      </main>
    </div>
  );
};

export default EquipoPage;
